5	// TestClassifyBucket pins the status → bucket mapping for every
6	// terminal-aligned status declared in agent/execute_bead_status.go. If a
7	// new ExecuteBeadStatus value is added there, this test must be updated
8	// to keep aggregations from silently bucketing it as "unknown".
9	func TestClassifyBucket(t *testing.T) {
10		cases := []struct {
11			name   string
12			status string
13			want   Bucket
14		}{
15			{"success", "success", BucketSuccess},
16			// already_satisfied counts as success per the Story 11
17			// locked decision.
18			{"already_satisfied", "already_satisfied", BucketSuccess},
19			{"no_changes", "no_changes", BucketNoChanges},
20			{"no_evidence_produced", "no_evidence_produced", BucketNoEvidence},
21			{"preserved_needs_review", "preserved_needs_review", BucketPreserved},
22			{"declined_needs_decomposition", "declined_needs_decomposition", BucketDecomposed},
23			{"review_request_changes", "review_request_changes", BucketReviewRejected},
24			{"review_block", "review_block", BucketReviewRejected},
25			{"review_malfunction", "review_malfunction", BucketReviewRejected},
26			{"land_conflict", "land_conflict", BucketLandConflict},
27			{"land_conflict_unresolvable", "land_conflict_unresolvable", BucketLandConflict},
28			{"land_conflict_needs_human", "land_conflict_needs_human", BucketLandConflict},
29			{"push_failed", "push_failed", BucketLandConflict},
30			{"push_conflict", "push_conflict", BucketLandConflict},
31			{"ratchet_failed", "ratchet_failed", BucketRatchetFailed},
32			{"execution_failed", "execution_failed", BucketExecFailed},
33			{"post_run_check_failed", "post_run_check_failed", BucketExecFailed},
34			{"structural_validation_failed", "structural_validation_failed", BucketExecFailed},
35			{"empty", "", BucketUnknown},
36			{"unrecognized", "future_status_xyz", BucketUnknown},
37		}
38		for _, tc := range cases {
39			t.Run(tc.name, func(t *testing.T) {
40				got := ClassifyBucket(tc.status)
41				if got != tc.want {
42					t.Fatalf("ClassifyBucket(%q) = %q, want %q", tc.status, got, tc.want)
43				}
44			})
45		}
46	}
47	
48	func TestBucketSuccessful(t *testing.T) {
49		if !BucketSuccess.Successful() {
50			t.Fatalf("BucketSuccess must be Successful()")
51		}
52		if !ClassifyBucket("already_satisfied").Successful() {
53			t.Fatalf("already_satisfied must classify as a successful bucket")
54		}
55		for _, b := range []Bucket{
56			BucketNoChanges, BucketNoEvidence, BucketPreserved,
57			BucketDecomposed, BucketReviewRejected, BucketLandConflict,
58			BucketRatchetFailed, BucketExecFailed, BucketUnknown,
59		} {
60			if b.Successful() {
61				t.Fatalf("bucket %q must not be Successful()", b)
62			}
63		}
64	}
