15	const (
16		runStoreSubdir = ".ddx/exec/runs"
17		bundlesSubdir  = ".ddx/executions"
18	)
19	
20	// LoadAttempts scans the FEAT-010 run-store first, then .ddx/executions
21	// bundles, and returns one Attempt per execute-bead try. When the same
22	// AttemptID appears in both sources the run-store record wins. Attempts
23	// are returned sorted by StartedAt ascending (newest last) so callers
24	// computing windowed aggregations can take a tail slice.
25	func LoadAttempts(workingDir string) ([]Attempt, error) {
26		enrich, err := loadRoutingEnrichment(workingDir)
27		if err != nil {
28			return nil, err
29		}
30	
31		out := make([]Attempt, 0, 64)
32		seen := make(map[string]bool)
33	
34		rs, err := loadFromRunStore(workingDir)
35		if err != nil {
36			return nil, err
37		}
38		for _, a := range rs {
39			applyEnrichment(&a, enrich)
40			a.Bucket = ClassifyBucket(a.Status)
41			a.Tier = TierKey(a.Harness, a.Model)
42			out = append(out, a)
43			seen[a.AttemptID] = true
44		}
45	
46		bd, err := loadFromBundles(workingDir)
47		if err != nil {
48			return nil, err
49		}
50		for _, a := range bd {
51			if seen[a.AttemptID] {
52				continue
53			}
54			applyEnrichment(&a, enrich)
55			a.Bucket = ClassifyBucket(a.Status)
56			a.Tier = TierKey(a.Harness, a.Model)
57			out = append(out, a)
58			seen[a.AttemptID] = true
59		}
60	
61		sort.SliceStable(out, func(i, j int) bool {
62			return out[i].StartedAt.Before(out[j].StartedAt)
63		})
64		return out, nil
65	}
66	
67	// TierKey is the canonical "harness/model" tier label used by other Story
68	// 11 surfaces. An empty model collapses to just the harness.
69	func TierKey(harness, model string) string {
70		if model == "" {
71			return harness
72		}
73		return harness + "/" + model
74	}
75	
76	// runRecord mirrors the FEAT-010 run-store JSON shape (subset). Mirrors
77	// server/state_runs.go runRecord; intentionally not shared so this package
78	// stays free of the server import graph.
79	type runRecord struct {
80		ID          string  `json:"id"`
81		Layer       string  `json:"layer"`
82		Status      string  `json:"status"`
83		Outcome     string  `json:"outcome"`
84		StartedAt   string  `json:"started_at"`
85		CompletedAt string  `json:"completed_at"`
86		BeadID      string  `json:"bead_id"`
87		Harness     string  `json:"harness"`
88		Provider    string  `json:"provider"`
89		Model       string  `json:"model"`
90		CostUSD     float64 `json:"cost_usd"`
91		DurationMs  int     `json:"duration_ms"`
92		ExitCode    int     `json:"exit_code"`
93		TokensIn    int     `json:"tokens_in"`
94		TokensOut   int     `json:"tokens_out"`
95	}
96	
97	func loadFromRunStore(workingDir string) ([]Attempt, error) {
98		dir := filepath.Join(workingDir, runStoreSubdir)
99		entries, err := os.ReadDir(dir)
100		if err != nil {
101			if os.IsNotExist(err) {
102				return nil, nil
103			}
104			return nil, fmt.Errorf("read run store: %w", err)
105		}
106		out := make([]Attempt, 0, len(entries))
107		for _, entry := range entries {
108			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") {
109				continue
110			}
111			raw, err := os.ReadFile(filepath.Join(dir, entry.Name()))
112			if err != nil {
113				continue
114			}
115			var rec runRecord
116			if err := json.Unmarshal(raw, &rec); err != nil || rec.ID == "" {
117				continue
118			}
119			// Only try-layer records correspond to execute-bead attempts.
120			// Run-layer records (per-invocation harness sessions) are noise
121			// for Story 11 aggregations; skip them. Empty layer is treated
122			// as try for forward-compat with writers that omit it.
123			layer := strings.ToLower(rec.Layer)
124			if layer != "" && layer != "try" {
125				continue
126			}
127			a := Attempt{
128				AttemptID:    rec.ID,
129				BeadID:       rec.BeadID,
130				Harness:      rec.Harness,
131				Provider:     rec.Provider,
132				Model:        rec.Model,
133				Status:       rec.Status,
134				Outcome:      rec.Outcome,
135				CostUSD:      rec.CostUSD,
136				DurationMS:   rec.DurationMs,
137				ExitCode:     rec.ExitCode,
138				InputTokens:  rec.TokensIn,
139				OutputTokens: rec.TokensOut,
140				StartedAt:    parseTime(rec.StartedAt),
141				FinishedAt:   parseTime(rec.CompletedAt),
142				Source:       SourceRunStore,
143			}
144			out = append(out, a)
145		}
146		return out, nil
147	}
