149	// bundleResult mirrors the subset of agent.ExecuteBeadResult this loader
150	// reads. Kept local so the package does not depend on the agent package.
151	type bundleResult struct {
152		BeadID     string    `json:"bead_id"`
153		AttemptID  string    `json:"attempt_id"`
154		Outcome    string    `json:"outcome"`
155		Status     string    `json:"status"`
156		Harness    string    `json:"harness"`
157		Provider   string    `json:"provider"`
158		Model      string    `json:"model"`
159		DurationMS int       `json:"duration_ms"`
160		CostUSD    float64   `json:"cost_usd"`
161		ExitCode   int       `json:"exit_code"`
162		StartedAt  time.Time `json:"started_at"`
163		FinishedAt time.Time `json:"finished_at"`
164	}
