166	func loadFromBundles(workingDir string) ([]Attempt, error) {
167		dir := filepath.Join(workingDir, bundlesSubdir)
168		entries, err := os.ReadDir(dir)
169		if err != nil {
170			if os.IsNotExist(err) {
171				return nil, nil
172			}
173			return nil, fmt.Errorf("read bundles dir: %w", err)
174		}
175		out := make([]Attempt, 0, len(entries))
176		for _, entry := range entries {
177			if !entry.IsDir() {
178				continue
179			}
180			bundleID := entry.Name()
181			resultPath := filepath.Join(dir, bundleID, "result.json")
182			raw, err := os.ReadFile(resultPath)
183			if err != nil {
184				continue
185			}
186			var res bundleResult
187			if err := json.Unmarshal(raw, &res); err != nil {
188				continue
189			}
190			attemptID := res.AttemptID
191			if attemptID == "" {
192				attemptID = bundleID
193			}
194			out = append(out, Attempt{
195				AttemptID:  attemptID,
196				BeadID:     res.BeadID,
197				Harness:    res.Harness,
198				Provider:   res.Provider,
199				Model:      res.Model,
200				Status:     res.Status,
201				Outcome:    res.Outcome,
202				CostUSD:    res.CostUSD,
203				DurationMS: res.DurationMS,
204				ExitCode:   res.ExitCode,
205				StartedAt:  res.StartedAt,
206				FinishedAt: res.FinishedAt,
207				Source:     SourceBundle,
208			})
209		}
210		return out, nil
211	}
