10	// writeFile materialises a path under workingDir, creating directories as
11	// needed. Test helper.
12	func writeFile(t *testing.T, workingDir, rel, body string) {
13		t.Helper()
14		full := filepath.Join(workingDir, rel)
15		if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
16			t.Fatalf("mkdir: %v", err)
17		}
18		if err := os.WriteFile(full, []byte(body), 0o644); err != nil {
19			t.Fatalf("write %s: %v", rel, err)
20		}
21	}
