457	// Create adds a new bead. Assigns defaults, validates, then persists.
458	func (s *Store) Create(b *Bead) error {
459		now := time.Now().UTC()
460		if b.ID == "" {
461			id, err := s.GenID()
462			if err != nil {
463				return err
464			}
465			b.ID = id
466		}
467		if b.IssueType == "" {
468			b.IssueType = DefaultType
469		}
470		if b.Status == "" {
471			// Creation is not a transition; the only status write that does not go
472			// through transitionLifecycleInPlace (TD-031 §3 transition matrix).
473			b.Status = DefaultStatus
474		}
475		b.CreatedAt = now
476		b.UpdatedAt = now
477	
478		// Validate after defaults are applied so hooks see final state
479		if err := s.validateBead(b); err != nil {
480			return err
481		}
482		// Story 15: an operator-prompt bead's execution may not create another
483		// operator-prompt bead. The execute-bead harness exports the actor's
484		// issue_type via DDX_ACTOR_ISSUE_TYPE; absent the env, the guard is a
485		// no-op (e.g. direct CLI use by a human operator).
486		if err := OperatorPromptMutationGuard(os.Getenv("DDX_ACTOR_ISSUE_TYPE"), b.IssueType); err != nil {
487			return err
488		}
489		// Run create hook
490		if err := s.runHook("validate-bead-create", b); err != nil {
491			return err
492		}
493	
494		return s.WithLock(func() error {
495			beads, _, err := s.readAllLatestRaw()
496			if err != nil {
497				return err
498			}
499			// Reject duplicate IDs
500			for _, e := range beads {
501				if e.ID == b.ID {
502					return fmt.Errorf("bead: duplicate id: %s", b.ID)
503				}
504			}
505			// Validate deps reference existing beads
506			depIDs := b.DepIDs()
507			if len(depIDs) > 0 {
508				existing := make(map[string]bool)
509				for _, e := range beads {
510					existing[e.ID] = true
511				}
512				for _, dep := range depIDs {
513					if !existing[dep] {
514						return fmt.Errorf("bead: dependency not found: %s", dep)
515					}
516				}
517			}
518			beads = append(beads, *b)
519			return s.WriteAll(beads)
520		})
521	}
