975	func (s *Store) AppendEvent(id string, event BeadEvent) error {
976		if event.CreatedAt.IsZero() {
977			event.CreatedAt = time.Now().UTC()
978		}
979		// Defense in depth: cap every event body regardless of caller. The
980		// reviewer write path separately persists the full stream to an artifact
981		// and emits a <=512-byte body; this cap catches anything else.
982		event.Body = capFieldBytes(event.Body)
983		event.Summary = capFieldBytes(event.Summary)
984		// Two storage shapes are possible here: inline Extra["events"] for active
985		// beads, and a sidecar attachment for closed/archived beads (ADR-004
986		// attachment model). When the bead has been externalized we append to the
987		// sidecar and leave the row untouched aside from updated_at.
988		var appendedToAttachment bool
989		if err := s.Update(id, func(b *Bead) {
990			if b.Extra == nil {
991				b.Extra = make(map[string]any)
992			}
993			if hasEventsAttachment(b) {
994				appendedToAttachment = true
995				return
996			}
997			var events []BeadEvent
998			if raw, ok := b.Extra["events"]; ok {
999				events = decodeBeadEvents(raw)
1000			}
1001			events = append(events, event)
1002			b.Extra["events"] = encodeEventsForExtra(events)
1003		}); err != nil {
1004			return err
1005		}
1006		if !appendedToAttachment {
1007			return nil
1008		}
1009		// Append to the sidecar under the store lock so concurrent readers and
1010		// writers see a consistent events log.
1011		return s.WithLock(func() error {
1012			existing, err := s.readEventsAttachment(id)
1013			if err != nil {
1014				return err
1015			}
1016			existing = append(existing, event)
1017			return s.writeEventsAttachment(id, existing)
1018		})
1019	}
