1057	func decodeBeadEvents(raw any) []BeadEvent {
1058		switch v := raw.(type) {
1059		case []BeadEvent:
1060			out := make([]BeadEvent, len(v))
1061			copy(out, v)
1062			return out
1063		case []any:
1064			out := make([]BeadEvent, 0, len(v))
1065			for _, item := range v {
1066				m, ok := item.(map[string]any)
1067				if !ok {
1068					continue
1069				}
1070				out = append(out, beadEventFromMap(m))
1071			}
1072			return out
1073		case []map[string]any:
1074			out := make([]BeadEvent, 0, len(v))
1075			for _, item := range v {
1076				out = append(out, beadEventFromMap(item))
1077			}
1078			return out
1079		default:
1080			return nil
1081		}
1082	}
