1084	func beadEventFromMap(m map[string]any) BeadEvent {
1085		e := BeadEvent{}
1086		if v, ok := m["kind"].(string); ok {
1087			e.Kind = v
1088		}
1089		if v, ok := m["summary"].(string); ok {
1090			e.Summary = v
1091		}
1092		if v, ok := m["body"].(string); ok {
1093			e.Body = v
1094		}
1095		if v, ok := m["actor"].(string); ok {
1096			e.Actor = v
1097		}
1098		if v, ok := m["source"].(string); ok {
1099			e.Source = v
1100		}
1101		if v, ok := m["created_at"].(string); ok {
1102			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
1103				e.CreatedAt = parsed
1104			}
1105		}
1106		return e
1107	}
