1289	// Reopen sets a bead's status back to open, clears claim fields, optionally
1290	// appends notes, and records an immutable reopen event — all in one atomic
1291	// lock acquisition.
1292	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1293		now := time.Now().UTC()
1294		return s.WithLock(func() error {
1295			beads, _, err := s.readAllLatestRaw()
1296			if err != nil {
1297				return err
1298			}
1299			found := false
1300			for i := range beads {
1301				if beads[i].ID != id {
1302					continue
1303				}
1304				b := &beads[i]
1305				if err := transitionLifecycleInPlace(b, StatusOpen, LifecycleTransitionOptions{
1306					ManualReopen: true,
1307				}); err != nil {
1308					return err
1309				}
1310				b.Owner = ""
1311				b.UpdatedAt = now
1312				if b.Extra == nil {
1313					b.Extra = make(map[string]any)
1314				}
1315				// Clear claim fields
1316				delete(b.Extra, "claimed-at")
1317				delete(b.Extra, "claimed-pid")
1318				delete(b.Extra, "claimed-machine")
1319				delete(b.Extra, "claimed-session")
1320				delete(b.Extra, "claimed-worktree")
1321				delete(b.Extra, "execute-loop-heartbeat-at")
1322				// Append notes
1323				if appendNotes != "" {
1324					if b.Notes != "" {
1325						b.Notes = b.Notes + "\n\n" + appendNotes
1326					} else {
1327						b.Notes = appendNotes
1328					}
1329				}
1330				// Record reopen event. If events were externalized at close,
1331				// pull them back inline so the active row carries the full
1332				// history again and the attachment ref is dropped.
1333				if hasEventsAttachment(b) {
1334					if err := s.inlineEventsInPlace(b); err != nil {
1335						return err
1336					}
1337					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1338				}
1339				var events []BeadEvent
1340				if raw, ok := b.Extra["events"]; ok {
1341					events = decodeBeadEvents(raw)
1342				}
1343				evt := BeadEvent{
1344					Kind:      "reopen",
1345					CreatedAt: now,
1346				}
1347				if reason != "" {
1348					evt.Summary = reason
1349				}
1350				events = append(events, evt)
1351				encoded := make([]map[string]any, 0, len(events))
1352				for _, e := range events {
1353					encoded = append(encoded, map[string]any{
1354						"kind":       e.Kind,
1355						"summary":    e.Summary,
1356						"body":       e.Body,
1357						"actor":      e.Actor,
1358						"created_at": e.CreatedAt,
1359						"source":     e.Source,
1360					})
1361				}
1362				b.Extra["events"] = encoded
1363				if err := s.validateBead(b); err != nil {
1364					return err
1365				}
1366				if err := s.runHook("validate-bead-update", b); err != nil {
1367					return err
1368				}
1369				found = true
1370				break
1371			}
1372			if !found {
1373				return fmt.Errorf("bead: not found: %s", id)
1374			}
1375			if err := s.WriteAll(beads); err != nil {
1376				return err
1377			}
1378			return s.RemoveClaimHeartbeat(id)
1379		})
1380	}
