1528	func activeRetryCooldown(b Bead, now time.Time) (time.Time, bool) {
1529		retryAfterStr := extraStringVal(b.Extra, ExtraRetryAfter)
1530		if retryAfterStr == "" {
1531			return time.Time{}, false
1532		}
1533		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1534		if err != nil {
1535			return time.Time{}, false
1536		}
1537		return retryAfter, retryAfter.After(now)
1538	}
1539	
1540	func lifecycleExecutionEligible(b Bead) (bool, bool) {
1541		eligible, ok := b.Extra[ExtraExecutionElig]
1542		if !ok {
1543			return true, false
1544		}
1545		val, isBool := eligible.(bool)
1546		if !isBool {
1547			return true, false
1548		}
1549		return val, true
1550	}
1551	
1552	func lifecycleSupersededBy(b Bead) string {
1553		return strings.TrimSpace(extraStringVal(b.Extra, "superseded-by"))
1554	}
