1593	// ReadyExecutionBreakdown is the lifecycle-derived queue snapshot used by the
1594	// worker when explaining an empty execution queue.
1595	type ReadyExecutionBreakdown struct {
1596		ExecutionReady            []string
1597		DependencyWaiting         []string
1598		ProposedOperatorAttention []string
1599		RetryCooldown             []string
1600		ExternalBlocked           []string
1601		NotEligible               []string
1602		Superseded                []string
1603		Epics                     []string
1604		EpicClosureCandidates     []string
1605		NextRetryAfter            string
1606		HumanReviewBlockedTotal   int
1607		HumanReviewBlockers       []HumanReviewBlockerPressure
1608	}
