1610	// HumanReviewBlockerPressure describes an open human-review blocker and the
1611	// number of active downstream beads that transitively depend on it.
1612	type HumanReviewBlockerPressure struct {
1613		ID                     string
1614		Title                  string
1615		Priority               int
1616		DownstreamBlockedCount int
1617	}
1618	
1619	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1620		out := ReadyExecutionBreakdown{}
1621		beads, err := s.ReadAll()
1622		if err != nil {
1623			return out, err
1624		}
1625		now := time.Now().UTC()
1626		var soonestRetry time.Time
1627		for _, entry := range s.classifyLifecycleQueue(beads, now) {
1628			switch entry.Decision.Bucket {
1629			case LifecycleBucketReady:
1630				out.ExecutionReady = append(out.ExecutionReady, entry.ID)
1631			case LifecycleBucketWaitingDependencies:
1632				out.DependencyWaiting = append(out.DependencyWaiting, entry.ID)
1633			case LifecycleBucketRetryCooldown:
1634				out.RetryCooldown = append(out.RetryCooldown, entry.ID)
1635				if !entry.RetryAfter.IsZero() && (soonestRetry.IsZero() || entry.RetryAfter.Before(soonestRetry)) {
1636					soonestRetry = entry.RetryAfter
1637				}
1638			case LifecycleBucketEpicContainer:
1639				if entry.EpicClosureCandidate {
1640					out.EpicClosureCandidates = append(out.EpicClosureCandidates, entry.ID)
1641				} else {
1642					out.Epics = append(out.Epics, entry.ID)
1643				}
1644			case LifecycleBucketNotEligible:
1645				out.NotEligible = append(out.NotEligible, entry.ID)
1646			case LifecycleBucketSuperseded:
1647				out.Superseded = append(out.Superseded, entry.ID)
1648			case LifecycleBucketBlockedExternal:
1649				out.ExternalBlocked = append(out.ExternalBlocked, entry.ID)
1650			case LifecycleBucketProposed:
1651				out.ProposedOperatorAttention = append(out.ProposedOperatorAttention, entry.ID)
1652			}
1653		}
1654		if !soonestRetry.IsZero() {
1655			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1656		}
1657		out.HumanReviewBlockers, out.HumanReviewBlockedTotal = humanReviewBlockerPressure(beads)
1658		return out, nil
1659	}
1660	
1661	func humanReviewBlockerPressure(beads []Bead) ([]HumanReviewBlockerPressure, int) {
1662		byID := make(map[string]Bead, len(beads))
1663		reverseDeps := make(map[string][]string, len(beads))
1664		for _, b := range beads {
1665			byID[b.ID] = b
1666			if !activeForDependencyPressure(b) {
1667				continue
1668			}
1669			for _, dep := range b.Dependencies {
1670				if dep.DependsOnID == "" {
1671					continue
1672				}
1673				reverseDeps[dep.DependsOnID] = append(reverseDeps[dep.DependsOnID], b.ID)
1674			}
1675		}
1676	
1677		var blockers []HumanReviewBlockerPressure
1678		totalBlocked := map[string]struct{}{}
1679		for _, b := range beads {
1680			if !isHumanReviewBlocker(b) {
1681				continue
1682			}
1683			seen := map[string]struct{}{}
1684			var walk func(string)
1685			walk = func(id string) {
1686				for _, childID := range reverseDeps[id] {
1687					if childID == b.ID {
1688						continue
1689					}
1690					child, ok := byID[childID]
1691					if !ok || !activeForDependencyPressure(child) {
1692						continue
1693					}
1694					if _, exists := seen[childID]; exists {
1695						continue
1696					}
1697					seen[childID] = struct{}{}
1698					totalBlocked[childID] = struct{}{}
1699					walk(childID)
1700				}
1701			}
1702			walk(b.ID)
1703			if len(seen) == 0 {
1704				// A proposed/needs-human bead with no active downstream is operator
1705				// attention only; it does not contribute to HumanReviewBlockers.
1706				continue
1707			}
1708			blockers = append(blockers, HumanReviewBlockerPressure{
1709				ID:                     b.ID,
1710				Title:                  b.Title,
1711				Priority:               b.Priority,
1712				DownstreamBlockedCount: len(seen),
1713			})
1714		}
1715	
1716		sort.SliceStable(blockers, func(i, j int) bool {
1717			if blockers[i].Priority != blockers[j].Priority {
1718				return blockers[i].Priority < blockers[j].Priority
1719			}
1720			return blockers[i].ID < blockers[j].ID
1721		})
1722		return blockers, len(totalBlocked)
1723	}
1724	
1725	func isHumanReviewBlocker(b Bead) bool {
1726		// Post-lifecycle: proposed status is the canonical operator-attention signal.
1727		if b.Status == StatusProposed {
1728			return true
1729		}
1730		// Legacy: open beads with investigation/human-review labels still count.
1731		if b.Status != StatusOpen {
1732			return false
1733		}
1734		for _, label := range b.Labels {
1735			switch label {
1736			case LabelNeedsHuman, LabelNeedsInvestigation, LabelNoChangesUnverified, LabelNoChangesUnjustified:
1737				return true
1738			}
1739		}
1740		return false
1741	}
1742	
1743	func activeForDependencyPressure(b Bead) bool {
1744		switch b.Status {
1745		case StatusClosed, StatusCancelled:
1746			return false
1747		default:
1748			return true
1749		}
1750	}
1751	
1752	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1753		beads, err := s.ReadAll()
1754		if err != nil {
1755			return nil, err
1756		}
1757	
1758		var ready []Bead
1759		for _, entry := range s.classifyLifecycleQueue(beads, time.Now().UTC()) {
1760			if entry.Decision.Bucket != LifecycleBucketReady {
1761				continue
1762			}
1763			if executionOnly {
1764				ready = append(ready, entry.Bead)
1765				continue
1766			}
1767			if entry.Status == StatusOpen {
1768				ready = append(ready, entry.Bead)
1769			}
1770		}
1771	
1772		sortBeadsForQueue(ready)
1773	
