2075	// DepAdd adds a dependency: id depends on depID.
2076	func (s *Store) DepAdd(id, depID string) error {
2077		return s.WithLock(func() error {
2078			beads, _, err := s.readAllLatestRaw()
2079			if err != nil {
2080				return err
2081			}
2082			var target *Bead
2083			depExists := false
2084			for i := range beads {
2085				if beads[i].ID == id {
2086					target = &beads[i]
2087				}
2088				if beads[i].ID == depID {
2089					depExists = true
2090				}
2091			}
2092			if target == nil {
2093				return fmt.Errorf("bead: not found: %s", id)
2094			}
2095			if !depExists {
2096				return fmt.Errorf("bead: dependency not found: %s", depID)
2097			}
2098			if id == depID {
2099				return fmt.Errorf("bead: cannot depend on self")
2100			}
2101			if target.HasDep(depID) {
2102				return nil // already exists
2103			}
2104	
2105			// Check for circular dependency
2106			depMap := make(map[string][]string)
2107			for _, b := range beads {
2108				depMap[b.ID] = b.DepIDs()
2109			}
2110			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
2111			if hasCycle(depMap, id) {
2112				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
2113			}
2114	
2115			target.AddDep(depID, "blocks")
2116			target.UpdatedAt = time.Now().UTC()
2117			return s.WriteAll(beads)
2118		})
2119	}
