2138			if archived, aerr := archive.ReadAll(); aerr == nil {
2139				seen := make(map[string]bool, len(beads))
2140				for _, b := range beads {
2141					seen[b.ID] = true
2142				}
2143				for _, b := range archived {
2144					if seen[b.ID] {
2145						continue
2146					}
2147					beads = append(beads, b)
2148				}
2149			}
2150		}
2151		byID := make(map[string]*Bead)
2152		for i := range beads {
2153			byID[beads[i].ID] = &beads[i]
2154		}
2155	
2156		if rootID != "" {
2157			target, ok := byID[rootID]
2158			if !ok {
2159				return "", fmt.Errorf("bead: not found: %s", rootID)
2160			}
2161			var sb strings.Builder
2162			// Walk up: show the dependency chain (what this node depends on)
2163			depChain := s.depChainUp(byID, rootID)
2164			if len(depChain) > 0 {
2165				// Print deps as the tree root(s), with the target as their child
2166				for _, depID := range depChain {
2167					if dep, ok := byID[depID]; ok {
2168						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
2169					}
2170				}
2171			}
2172			// Print the target node
2173			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
2174			// Print dependents (what depends on this node)
2175			var children []string
2176			for _, other := range sortedKeys(byID) {
2177				if byID[other].HasDep(rootID) {
2178					children = append(children, other)
2179				}
2180			}
2181			for _, child := range children {
2182				s.printTree(&sb, byID, child, "  ", true)
2183			}
2184			return sb.String(), nil
2185		}
2186	
2187		// Find roots (beads that have no dependencies themselves)
2188		var roots []string
2189		for _, b := range beads {
2190			if len(b.Dependencies) == 0 {
2191				roots = append(roots, b.ID)
2192			}
2193		}
2194		sort.Strings(roots)
2195	
2196		var sb strings.Builder
2197		for i, root := range roots {
2198			s.printTree(&sb, byID, root, "", i == len(roots)-1)
2199		}
2200		return sb.String(), nil
2201	}
