2282			if root != "" {
2283				return filepath.Base(root)
2284			}
2285		}
2286		// Fall back to the provided working dir, then cwd.
2287		if workingDir != "" {
2288			return filepath.Base(workingDir)
2289		}
2290		if wd, err := os.Getwd(); err == nil {
2291			return filepath.Base(wd)
